{
  "name": "Sistem Persuratan Digital (E-Surat)",
  "description": "A comprehensive digital mail management system for incoming and outgoing letters with role-based access control (Admin, Incoming Staff, Outgoing Staff). Featuring AI-powered letter summarization.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  ADMIN = 'ADMIN',
  STAF_MASUK = 'STAF_MASUK',
  STAF_KELUAR = 'STAF_KELUAR'
}

export interface User {
  id: string;
  username: string;
  name: string;
  role: UserRole;
}

export type LetterType = 'INCOMING' | 'OUTGOING';

export interface Letter {
  id: string;
  type: LetterType;
  referenceNumber: string; // Nomor Surat
  date: string;
  sender: string; // Pengirim (for Incoming) or Penerima (for Outgoing)
  subject: string; // Perihal
  description?: string; // Ringkasan/Isi
  fileUrl?: string;
  createdAt: number;
}

export interface AppState {
  currentUser: User | null;
  letters: Letter[];
  users: User[];
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeLetter = async (text: string) => {
  if (!text || !process.env.API_KEY) return null;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this letter text and extract key information in Indonesian: ${text}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "Ringkasan singkat surat" },
            category: { type: Type.STRING, description: "Kategori surat (e.g., Undangan, Pemberitahuan, Izin)" },
            priority: { type: Type.STRING, description: "Tingkat kepentingan (Tinggi, Sedang, Rendah)" }
          },
          required: ["summary", "category", "priority"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return null;
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, UserRole, Letter, LetterType } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import LetterModule from './components/LetterModule';
import UserManagement from './components/UserManagement';
import Auth from './components/Auth';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [letters, setLetters] = useState<Letter[]>([]);
  const [users, setUsers] = useState<User[]>([]);

  // Initialize data from localStorage
  useEffect(() => {
    const storedLetters = localStorage.getItem('esurat_letters');
    const storedUsers = localStorage.getItem('esurat_users');
    const storedAuth = localStorage.getItem('esurat_auth');

    if (storedLetters) setLetters(JSON.parse(storedLetters));
    if (storedUsers) {
      setUsers(JSON.parse(storedUsers));
    } else {
      // Default users if empty
      const defaultUsers: User[] = [
        { id: '1', username: 'admin', name: 'Administrator', role: UserRole.ADMIN },
        { id: '2', username: 'masuk', name: 'Staf Surat Masuk', role: UserRole.STAF_MASUK },
        { id: '3', username: 'keluar', name: 'Staf Surat Keluar', role: UserRole.STAF_KELUAR },
      ];
      setUsers(defaultUsers);
      localStorage.setItem('esurat_users', JSON.stringify(defaultUsers));
    }

    if (storedAuth) setCurrentUser(JSON.parse(storedAuth));
  }, []);

  // Persistence
  useEffect(() => {
    localStorage.setItem('esurat_letters', JSON.stringify(letters));
  }, [letters]);

  useEffect(() => {
    localStorage.setItem('esurat_users', JSON.stringify(users));
  }, [users]);

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('esurat_auth');
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('esurat_auth', JSON.stringify(user));
    setActiveTab('dashboard');
  };

  const addLetter = (letter: Omit<Letter, 'id' | 'createdAt'>) => {
    const newLetter: Letter = {
      ...letter,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now()
    };
    setLetters(prev => [newLetter, ...prev]);
  };

  const deleteLetter = (id: string) => {
    setLetters(prev => prev.filter(l => l.id !== id));
  };

  const updateLetter = (updated: Letter) => {
    setLetters(prev => prev.map(l => l.id === updated.id ? updated : l));
  };

  if (!currentUser) {
    return <Auth onLogin={handleLogin} users={users} />;
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        role={currentUser.role} 
        activeTab={activeTab} 
        onTabChange={setActiveTab} 
        user={currentUser}
        onLogout={handleLogout}
      />

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <header className="mb-8">
          <h1 className="text-2xl font-bold text-slate-800 capitalize">
            {activeTab.replace('-', ' ')}
          </h1>
          <p className="text-slate-500">Selamat datang kembali, {currentUser.name}</p>
        </header>

        {activeTab === 'dashboard' && <Dashboard letters={letters} users={users} />}

        {(activeTab === 'surat-masuk' || (currentUser.role === UserRole.ADMIN && activeTab === 'all-letters')) && (
          <LetterModule 
            type="INCOMING" 
            letters={letters.filter(l => l.type === 'INCOMING')} 
            onAdd={addLetter}
            onDelete={deleteLetter}
            onUpdate={updateLetter}
            canManage={currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.STAF_MASUK}
          />
        )}

        {(activeTab === 'surat-keluar' || (currentUser.role === UserRole.ADMIN && activeTab === 'all-letters')) && (
          <LetterModule 
            type="OUTGOING" 
            letters={letters.filter(l => l.type === 'OUTGOING')} 
            onAdd={addLetter}
            onDelete={deleteLetter}
            onUpdate={updateLetter}
            canManage={currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.STAF_KELUAR}
          />
        )}

        {activeTab === 'users' && currentUser.role === UserRole.ADMIN && (
          <UserManagement 
            users={users} 
            onUpdateUsers={(updated) => setUsers(updated)} 
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { User, UserRole } from '../types';

interface SidebarProps {
