    { id: 'dashboard', label: 'Dashboard', icon: '📊', roles: [UserRole.ADMIN, UserRole.STAF_MASUK, UserRole.STAF_KELUAR] },
    { id: 'surat-masuk', label: 'Surat Masuk', icon: '📥', roles: [UserRole.ADMIN, UserRole.STAF_MASUK] },
    { id: 'surat-keluar', label: 'Surat Keluar', icon: '📤', roles: [UserRole.ADMIN, UserRole.STAF_KELUAR] },
    { id: 'users', label: 'Manajemen User', icon: '👥', roles: [UserRole.ADMIN] },
  ];

  return (
    <aside className="w-64 bg-indigo-900 text-white flex flex-col h-full shadow-xl">
      <div className="p-6">
        <div className="flex items-center gap-3 mb-8">
          <div className="w-10 h-10 bg-indigo-500 rounded-lg flex items-center justify-center text-xl font-bold shadow-lg">
            ES
          </div>
          <div>
            <h1 className="font-bold text-lg leading-none">E-Surat</h1>
            <span className="text-xs text-indigo-300">Digital Archive</span>
          </div>
        </div>

        <nav className="space-y-1">
          {menuItems.filter(item => item.roles.includes(role)).map(item => (
            <button
              key={item.id}
              onClick={() => onTabChange(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                activeTab === item.id 
                  ? 'bg-indigo-700 text-white shadow-inner' 
                  : 'hover:bg-indigo-800 text-indigo-100'
              }`}
            >
              <span className="text-xl">{item.icon}</span>
              <span className="font-medium">{item.label}</span>
            </button>
          ))}
        </nav>
      </div>

      <div className="mt-auto p-6 border-t border-indigo-800">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 bg-slate-200 rounded-full flex items-center justify-center text-indigo-900 font-bold">
            {user.name.charAt(0)}
          </div>
          <div className="overflow-hidden">
            <p className="font-semibold truncate">{user.name}</p>
            <p className="text-xs text-indigo-300 uppercase tracking-wider">{user.role}</p>
          </div>
        </div>
        <button 
          onClick={onLogout}
          className="w-full flex items-center justify-center gap-2 px-4 py-2 bg-indigo-800 hover:bg-red-600 rounded-lg transition-colors text-sm font-medium"
        >
          <span>🚪</span> Keluar
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;

import React from 'react';
import { Letter, User } from '../types';

interface DashboardProps {
  letters: Letter[];
  users: User[];
}

const Dashboard: React.FC<DashboardProps> = ({ letters, users }) => {
  const inCount = letters.filter(l => l.type === 'INCOMING').length;
  const outCount = letters.filter(l => l.type === 'OUTGOING').length;

  const stats = [
    { label: 'Total Surat Masuk', value: inCount, color: 'bg-emerald-500', icon: '📥' },
    { label: 'Total Surat Keluar', value: outCount, color: 'bg-blue-500', icon: '📤' },
    { label: 'Total User Sistem', value: users.length, color: 'bg-amber-500', icon: '👥' },
    { label: 'Aktivitas Hari Ini', value: letters.filter(l => new Date(l.createdAt).toDateString() === new Date().toDateString()).length, color: 'bg-indigo-500', icon: '⚡' },
  ];

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
            <div className={`${stat.color} text-white w-12 h-12 rounded-xl flex items-center justify-center text-2xl shadow-lg`}>
              {stat.icon}
            </div>
            <div>
              <p className="text-sm font-medium text-slate-500">{stat.label}</p>
              <p className="text-2xl font-bold text-slate-800">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold mb-4 text-slate-800">Aktivitas Terkini</h3>
          <div className="space-y-4">
            {letters.slice(0, 5).length > 0 ? (
              letters.slice(0, 5).map(letter => (
                <div key={letter.id} className="flex items-center gap-4 p-3 hover:bg-slate-50 rounded-xl transition-colors">
                  <div className={`w-2 h-10 rounded-full ${letter.type === 'INCOMING' ? 'bg-emerald-400' : 'bg-blue-400'}`}></div>
                  <div className="flex-1 min-w-0">
                    <p className="font-semibold text-slate-800 truncate">{letter.subject}</p>
                    <p className="text-xs text-slate-500">{letter.referenceNumber} • {new Date(letter.createdAt).toLocaleDateString()}</p>
                  </div>
                  <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase ${
                    letter.type === 'INCOMING' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'
                  }`}>
                    {letter.type === 'INCOMING' ? 'Masuk' : 'Keluar'}
                  </span>
                </div>
              ))
            ) : (
              <p className="text-center py-8 text-slate-400">Belum ada aktivitas surat.</p>
            )}
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold mb-4 text-slate-800">Statistik Cepat</h3>
          <div className="relative h-48 flex items-end justify-around gap-4 pt-8">
             <div className="flex flex-col items-center gap-2 w-full max-w-[80px]">
                <div className="w-full bg-emerald-500 rounded-t-lg transition-all duration-500" style={{ height: `${(inCount / Math.max(inCount + outCount, 1)) * 100}%` }}></div>
                <span className="text-xs font-bold text-slate-600">Masuk</span>
             </div>
             <div className="flex flex-col items-center gap-2 w-full max-w-[80px]">
                <div className="w-full bg-blue-500 rounded-t-lg transition-all duration-500" style={{ height: `${(outCount / Math.max(inCount + outCount, 1)) * 100}%` }}></div>
                <span className="text-xs font-bold text-slate-600">Keluar</span>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Letter, LetterType } from '../types';
import { analyzeLetter } from '../services/geminiService';

interface LetterModuleProps {
  type: LetterType;
  letters: Letter[];
  onAdd: (letter: Omit<Letter, 'id' | 'createdAt'>) => void;
  onDelete: (id: string) => void;
  onUpdate: (letter: Letter) => void;
  canManage: boolean;
}

const LetterModule: React.FC<LetterModuleProps> = ({ type, letters, onAdd, onDelete, onUpdate, canManage }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingLetter, setEditingLetter] = useState<Letter | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const [formData, setFormData] = useState({
    referenceNumber: '',
    date: new Date().toISOString().split('T')[0],
    sender: '',
    subject: '',
    description: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingLetter) {
      onUpdate({ ...editingLetter, ...formData });
      setEditingLetter(null);
    } else {
      onAdd({ ...formData, type });
    }
    setFormData({
      referenceNumber: '',
      date: new Date().toISOString().split('T')[0],
      sender: '',
      subject: '',
      description: ''
    });
    setShowForm(false);
  };

  const handleEdit = (letter: Letter) => {
    setFormData({
      referenceNumber: letter.referenceNumber,
      date: letter.date,
      sender: letter.sender,
      subject: letter.subject,
      description: letter.description || ''
    });
    setEditingLetter(letter);
    setShowForm(true);
  };

  const handleAnalyze = async () => {
    if (!formData.description) return alert("Masukkan isi surat terlebih dahulu untuk dianalisis.");
    setIsAnalyzing(true);
    const result = await analyzeLetter(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        description: `Analisis AI:\nRingkasan: ${result.summary}\nKategori: ${result.category}\nPrioritas: ${result.priority}\n\nIsi Asli:\n${prev.description}`
      }));
    }
    setIsAnalyzing(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="relative flex-1 max-w-xs">
           <span className="absolute left-3 top-2.5">🔍</span>
           <input 
            type="text" 
            placeholder="Cari surat..." 
            className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-sm shadow-sm"
           />
        </div>
        {canManage && (
          <button 
            onClick={() => { setShowForm(true); setEditingLetter(null); }}
            className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2"
          >
            <span>+</span> {type === 'INCOMING' ? 'Tambah Surat Masuk' : 'Tambah Surat Keluar'}
          </button>
        )}
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Tgl / No. Surat</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">{type === 'INCOMING' ? 'Pengirim' : 'Penerima'}</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Perihal</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Aksi</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {letters.length > 0 ? (
              letters.map(letter => (
                <tr key={letter.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4">
                    <p className="font-semibold text-slate-800">{new Date(letter.date).toLocaleDateString('id-ID')}</p>
                    <p className="text-xs text-slate-500 font-mono">{letter.referenceNumber}</p>
                  </td>
                  <td className="px-6 py-4 font-medium text-slate-700">{letter.sender}</td>
                  <td className="px-6 py-4">
                    <p className="text-slate-800 line-clamp-1">{letter.subject}</p>
                  </td>
                  <td className="px-6 py-4 text-right space-x-2">
                    {canManage && (
                      <>
                        <button onClick={() => handleEdit(letter)} className="text-indigo-600 hover:text-indigo-800 text-sm font-bold px-3 py-1 hover:bg-indigo-50 rounded-lg transition-colors">Edit</button>
                        <button onClick={() => onDelete(letter.id)} className="text-red-500 hover:text-red-700 text-sm font-bold px-3 py-1 hover:bg-red-50 rounded-lg transition-colors">Hapus</button>
                      </>
                    )}
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={4} className="px-6 py-12 text-center text-slate-400">Belum ada data surat tersedia.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {showForm && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-indigo-50/50">
              <h2 className="text-xl font-bold text-indigo-900">
                {editingLetter ? 'Ubah' : 'Tambah'} {type === 'INCOMING' ? 'Surat Masuk' : 'Surat Keluar'}
              </h2>
              <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-5">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Nomor Surat</label>
                  <input 
                    required 
                    value={formData.referenceNumber} 
                    onChange={e => setFormData({...formData, referenceNumber: e.target.value})}
                    className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                    placeholder="Contoh: 001/SK/2023"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Tanggal</label>
                  <input 
                    type="date" 
                    required 
                    value={formData.date} 
                    onChange={e => setFormData({...formData, date: e.target.value})}
                    className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">{type === 'INCOMING' ? 'Asal / Pengirim' : 'Tujuan / Penerima'}</label>
                <input 
                  required 
                  value={formData.sender} 
                  onChange={e => setFormData({...formData, sender: e.target.value})}
                  className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  placeholder={type === 'INCOMING' ? "Instansi Pengirim" : "Instansi Penerima"}
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">Perihal</label>
                <input 
                  required 
                  value={formData.subject} 
                  onChange={e => setFormData({...formData, subject: e.target.value})}
                  className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  placeholder="Ringkasan singkat perihal surat"
                />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between items-center">
                  <label className="text-sm font-bold text-slate-700">Isi / Ringkasan Surat</label>
                  <button 
                    type="button" 
                    onClick={handleAnalyze} 
                    disabled={isAnalyzing}
                    className="text-xs font-bold text-indigo-600 hover:text-indigo-800 disabled:opacity-50"
                  >
                    {isAnalyzing ? 'Menganalisis...' : '✨ Analisis AI'}
                  </button>
                </div>
                <textarea 
                  rows={4} 
                  value={formData.description} 
                  onChange={e => setFormData({...formData, description: e.target.value})}
                  className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none" 
                  placeholder="Ketik isi atau ringkasan surat di sini..."
                />
              </div>

              <div className="flex justify-end gap-3 pt-4">
                <button type="button" onClick={() => setShowForm(false)} className="px-6 py-2.5 text-slate-500 font-bold hover:bg-slate-100 rounded-xl transition-colors">Batal</button>
                <button type="submit" className="px-8 py-2.5 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all">
                  {editingLetter ? 'Simpan Perubahan' : 'Simpan Surat'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default LetterModule;

import React, { useState } from 'react';
import { User, UserRole } from '../types';

interface UserManagementProps {
  users: User[];
  onUpdateUsers: (users: User[]) => void;
}

const UserManagement: React.FC<UserManagementProps> = ({ users, onUpdateUsers }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [formData, setFormData] = useState({
    username: '',
    name: '',
    role: UserRole.STAF_MASUK
  });

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      ...formData
    };
    onUpdateUsers([...users, newUser]);
    setFormData({ username: '', name: '', role: UserRole.STAF_MASUK });
    setIsAdding(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Yakin ingin menghapus user ini?')) {
      onUpdateUsers(users.filter(u => u.id !== id));
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-end">
        <button 
          onClick={() => setIsAdding(true)}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2"
        >
          <span>+</span> Tambah User Baru
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Nama Lengkap</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Username</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Role</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Aksi</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {users.map(user => (
              <tr key={user.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-6 py-4">
                  <p className="font-semibold text-slate-800">{user.name}</p>
                </td>
                <td className="px-6 py-4 font-mono text-sm text-slate-500">{user.username}</td>
                <td className="px-6 py-4">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase ${
                    user.role === UserRole.ADMIN ? 'bg-purple-100 text-purple-700' : 
                    user.role === UserRole.STAF_MASUK ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'
