export default Auth;

export enum UserRole {
  ADMIN = 'ADMIN',
  STAF_MASUK = 'STAF_MASUK',
  STAF_KELUAR = 'STAF_KELUAR'
}

export interface User {
  id: string;
  username: string;
  name: string;
  role: UserRole;
}

export type LetterType = 'INCOMING' | 'OUTGOING';

export interface Disposition {
  recipient: string; // Diteruskan kepada (Nama/Jabatan)
  instruction: string; // Instruksi/Pesan pimpinan
  date: string; // Tanggal disposisi
  status: 'Menunggu' | 'Proses' | 'Selesai';
}

export interface Letter {
  id: string;
  type: LetterType;
  referenceNumber: string; // Nomor Surat
  date: string;
  sender: string; // Pengirim (for Incoming) or Penerima (for Outgoing)
  subject: string; // Perihal
  description?: string; // Ringkasan/Isi
  fileUrl?: string;
  createdAt: number;
  disposition?: Disposition; // Tambahan untuk Surat Masuk
}

export interface AppState {
  currentUser: User | null;
  letters: Letter[];
  users: User[];
}

import React, { useState } from 'react';
import { Letter, LetterType, Disposition, UserRole } from '../types';
import { analyzeLetter } from '../services/geminiService';

interface LetterModuleProps {
  type: LetterType;
  letters: Letter[];
  onAdd: (letter: Omit<Letter, 'id' | 'createdAt'>) => void;
  onDelete: (id: string) => void;
  onUpdate: (letter: Letter) => void;
  canManage: boolean;
  userRole?: UserRole; // Added to check for Admin role in disposition
}

const LetterModule: React.FC<LetterModuleProps> = ({ type, letters, onAdd, onDelete, onUpdate, canManage, userRole }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingLetter, setEditingLetter] = useState<Letter | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showDisposition, setShowDisposition] = useState(false);

  const [formData, setFormData] = useState({
    referenceNumber: '',
    date: new Date().toISOString().split('T')[0],
    sender: '',
    subject: '',
    description: '',
    disposition: undefined as Disposition | undefined
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingLetter) {
      onUpdate({ ...editingLetter, ...formData });
      setEditingLetter(null);
    } else {
      onAdd({ ...formData, type });
    }
    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setFormData({
      referenceNumber: '',
      date: new Date().toISOString().split('T')[0],
      sender: '',
      subject: '',
      description: '',
      disposition: undefined
    });
    setShowDisposition(false);
  };

  const handleEdit = (letter: Letter) => {
    setFormData({
      referenceNumber: letter.referenceNumber,
      date: letter.date,
      sender: letter.sender,
      subject: letter.subject,
      description: letter.description || '',
      disposition: letter.disposition
    });
    setShowDisposition(!!letter.disposition);
    setEditingLetter(letter);
    setShowForm(true);
  };

  const handleAnalyze = async () => {
    if (!formData.description) return alert("Masukkan isi surat terlebih dahulu untuk dianalisis.");
    setIsAnalyzing(true);
    const result = await analyzeLetter(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        description: `Analisis AI:\nRingkasan: ${result.summary}\nKategori: ${result.category}\nPrioritas: ${result.priority}\n\nIsi Asli:\n${prev.description}`
      }));
    }
    setIsAnalyzing(false);
  };

  const updateDisposition = (field: keyof Disposition, value: string) => {
    const currentDisp = formData.disposition || { recipient: '', instruction: '', date: new Date().toISOString().split('T')[0], status: 'Menunggu' };
    setFormData({
      ...formData,
      disposition: { ...currentDisp, [field]: value }
    });
  };

  const isAdmin = userRole === UserRole.ADMIN;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="relative flex-1 max-w-xs">
           <span className="absolute left-3 top-2.5">🔍</span>
           <input 
            type="text" 
            placeholder="Cari surat..." 
            className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-sm shadow-sm"
           />
        </div>
        {canManage && (
          <button 
            onClick={() => { resetForm(); setShowForm(true); }}
            className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2"
          >
            <span>+</span> {type === 'INCOMING' ? 'Tambah Surat Masuk' : 'Tambah Surat Keluar'}
          </button>
        )}
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Tgl / No. Surat</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">{type === 'INCOMING' ? 'Pengirim' : 'Penerima'}</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Perihal</th>
              {type === 'INCOMING' && <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Disposisi</th>}
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Aksi</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {letters.length > 0 ? (
              letters.map(letter => (
                <tr key={letter.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-6 py-4">
                    <p className="font-semibold text-slate-800">{new Date(letter.date).toLocaleDateString('id-ID')}</p>
                    <p className="text-xs text-slate-500 font-mono">{letter.referenceNumber}</p>
                  </td>
                  <td className="px-6 py-4 font-medium text-slate-700">{letter.sender}</td>
                  <td className="px-6 py-4">
                    <p className="text-slate-800 line-clamp-1">{letter.subject}</p>
                  </td>
                  {type === 'INCOMING' && (
                    <td className="px-6 py-4">
                      {letter.disposition ? (
                        <div className="flex flex-col gap-1">
                          <span className="px-2 py-0.5 bg-amber-100 text-amber-700 text-[10px] font-bold rounded-md w-fit">Terdisposisi</span>
                          <span className="text-[10px] text-slate-500 italic truncate max-w-[120px]">{letter.disposition.recipient}</span>
                        </div>
                      ) : (
                        <span className="px-2 py-0.5 bg-slate-100 text-slate-400 text-[10px] font-bold rounded-md w-fit">Belum Ada</span>
                      )}
                    </td>
                  )}
                  <td className="px-6 py-4 text-right space-x-2 whitespace-nowrap">
                    {canManage && (
                      <>
                        <button onClick={() => handleEdit(letter)} className="text-indigo-600 hover:text-indigo-800 text-sm font-bold px-3 py-1 hover:bg-indigo-50 rounded-lg transition-colors">Edit</button>
                        <button onClick={() => onDelete(letter.id)} className="text-red-500 hover:text-red-700 text-sm font-bold px-3 py-1 hover:bg-red-50 rounded-lg transition-colors">Hapus</button>
                      </>
                    )}
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={type === 'INCOMING' ? 5 : 4} className="px-6 py-12 text-center text-slate-400">Belum ada data surat tersedia.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {showForm && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white w-full max-w-3xl rounded-3xl shadow-2xl overflow-y-auto max-h-[90vh] animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-indigo-50/50 sticky top-0 bg-white z-10">
              <h2 className="text-xl font-bold text-indigo-900">
                {editingLetter ? 'Ubah' : 'Tambah'} {type === 'INCOMING' ? 'Surat Masuk' : 'Surat Keluar'}
              </h2>
              <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Nomor Surat</label>
                  <input 
                    required 
                    value={formData.referenceNumber} 
                    onChange={e => setFormData({...formData, referenceNumber: e.target.value})}
                    className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                    placeholder="Contoh: 001/SK/2023"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Tanggal Surat</label>
                  <input 
                    type="date" 
                    required 
                    value={formData.date} 
                    onChange={e => setFormData({...formData, date: e.target.value})}
                    className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">{type === 'INCOMING' ? 'Asal / Pengirim' : 'Tujuan / Penerima'}</label>
                <input 
                  required 
                  value={formData.sender} 
                  onChange={e => setFormData({...formData, sender: e.target.value})}
                  className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  placeholder={type === 'INCOMING' ? "Instansi Pengirim" : "Instansi Penerima"}
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">Perihal</label>
                <input 
                  required 
                  value={formData.subject} 
                  onChange={e => setFormData({...formData, subject: e.target.value})}
                  className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  placeholder="Ringkasan singkat perihal surat"
                />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between items-center">
                  <label className="text-sm font-bold text-slate-700">Isi / Ringkasan Surat</label>
                  <button 
                    type="button" 
                    onClick={handleAnalyze} 
                    disabled={isAnalyzing}
                    className="text-xs font-bold text-indigo-600 hover:text-indigo-800 disabled:opacity-50"
                  >
                    {isAnalyzing ? 'Menganalisis...' : '✨ Analisis AI'}
                  </button>
                </div>
                <textarea 
                  rows={3} 
                  value={formData.description} 
                  onChange={e => setFormData({...formData, description: e.target.value})}
                  className="w-full px-4 py-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none" 
                  placeholder="Ketik isi atau ringkasan surat di sini..."
                />
              </div>

              {/* SECTION DISPOSISI (HANYA SURAT MASUK) */}
              {type === 'INCOMING' && (
                <div className="border-2 border-dashed border-amber-200 rounded-2xl p-6 bg-amber-50/30 space-y-4">
                  <div className="flex justify-between items-center">
                    <h3 className="text-md font-bold text-amber-900 flex items-center gap-2">
                      <span className="text-xl">📝</span> Lembar Disposisi
                    </h3>
                    {!showDisposition && (
                      <button 
                        type="button" 
                        onClick={() => setShowDisposition(true)}
                        className="text-xs font-bold text-amber-700 hover:text-amber-900"
                      >
                        + Tambah Disposisi
                      </button>
                    )}
                  </div>

                  {showDisposition && (
                    <div className="grid grid-cols-1 gap-4 animate-in slide-in-from-top-2 duration-300">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="space-y-1">
                          <label className="text-xs font-bold text-amber-800">Diteruskan Kepada</label>
                          <input 
                            readOnly={!isAdmin}
                            value={formData.disposition?.recipient || ''}
                            onChange={e => updateDisposition('recipient', e.target.value)}
                            className="w-full px-3 py-2 border border-amber-200 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none bg-white text-sm" 
                            placeholder="Contoh: Kabag Umum / Staf IT"
                          />
                        </div>
                        <div className="space-y-1">
                          <label className="text-xs font-bold text-amber-800">Status Tindak Lanjut</label>
                          <select 
                            disabled={!isAdmin}
                            value={formData.disposition?.status || 'Menunggu'}
                            onChange={e => updateDisposition('status', e.target.value as any)}
                            className="w-full px-3 py-2 border border-amber-200 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none bg-white text-sm"
                          >
                            <option value="Menunggu">Menunggu</option>
                            <option value="Proses">Proses</option>
                            <option value="Selesai">Selesai</option>
                          </select>
                        </div>
                      </div>
                      <div className="space-y-1">
                        <label className="text-xs font-bold text-amber-800">Instruksi Pimpinan</label>
                        <textarea 
                          readOnly={!isAdmin}
                          rows={2} 
                          value={formData.disposition?.instruction || ''}
                          onChange={e => updateDisposition('instruction', e.target.value)}
                          className="w-full px-3 py-2 border border-amber-200 rounded-lg focus:ring-2 focus:ring-amber-500 outline-none bg-white text-sm resize-none" 
                          placeholder="Instruksi tindak lanjut surat..."
                        />
                      </div>
                      {!isAdmin && (
                        <p className="text-[10px] text-amber-600 italic">* Hanya Administrator yang dapat merubah instruksi disposisi.</p>
                      )}
                    </div>
                  )}
                </div>
              )}

              <div className="flex justify-end gap-3 pt-4 sticky bottom-0 bg-white py-4 border-t border-slate-100">
                <button type="button" onClick={() => setShowForm(false)} className="px-6 py-2.5 text-slate-500 font-bold hover:bg-slate-100 rounded-xl transition-colors">Batal</button>
                <button type="submit" className="px-8 py-2.5 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all">
                  {editingLetter ? 'Simpan Perubahan' : 'Simpan Surat'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default LetterModule;

import React, { useState, useEffect, useMemo } from 'react';
import { User, UserRole, Letter, LetterType } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import LetterModule from './components/LetterModule';
import UserManagement from './components/UserManagement';
import Auth from './components/Auth';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [letters, setLetters] = useState<Letter[]>([]);
  const [users, setUsers] = useState<User[]>([]);

  // Initialize data from localStorage
  useEffect(() => {
    const storedLetters = localStorage.getItem('esurat_letters');
    const storedUsers = localStorage.getItem('esurat_users');
    const storedAuth = localStorage.getItem('esurat_auth');

    if (storedLetters) setLetters(JSON.parse(storedLetters));
    if (storedUsers) {
      setUsers(JSON.parse(storedUsers));
    } else {
      // Default users if empty
      const defaultUsers: User[] = [
        { id: '1', username: 'admin', name: 'Administrator', role: UserRole.ADMIN },
        { id: '2', username: 'masuk', name: 'Staf Surat Masuk', role: UserRole.STAF_MASUK },
        { id: '3', username: 'keluar', name: 'Staf Surat Keluar', role: UserRole.STAF_KELUAR },
      ];
      setUsers(defaultUsers);
      localStorage.setItem('esurat_users', JSON.stringify(defaultUsers));
    }

    if (storedAuth) setCurrentUser(JSON.parse(storedAuth));
  }, []);

  // Persistence
  useEffect(() => {
    localStorage.setItem('esurat_letters', JSON.stringify(letters));
  }, [letters]);

  useEffect(() => {
    localStorage.setItem('esurat_users', JSON.stringify(users));
  }, [users]);

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('esurat_auth');
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('esurat_auth', JSON.stringify(user));
    setActiveTab('dashboard');
  };

  const addLetter = (letter: Omit<Letter, 'id' | 'createdAt'>) => {
    const newLetter: Letter = {
      ...letter,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: Date.now()
    };
    setLetters(prev => [newLetter, ...prev]);
  };

  const deleteLetter = (id: string) => {
    setLetters(prev => prev.filter(l => l.id !== id));
  };

  const updateLetter = (updated: Letter) => {
    setLetters(prev => prev.map(l => l.id === updated.id ? updated : l));
  };

  if (!currentUser) {
    return <Auth onLogin={handleLogin} users={users} />;
  }

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <Sidebar 
        role={currentUser.role} 
        activeTab={activeTab} 
        onTabChange={setActiveTab} 
        user={currentUser}
        onLogout={handleLogout}
      />

      <main className="flex-1 overflow-y-auto p-4 md:p-8">
        <header className="mb-8">
          <h1 className="text-2xl font-bold text-slate-800 capitalize">
            {activeTab.replace('-', ' ')}
          </h1>
          <p className="text-slate-500">Selamat datang kembali, {currentUser.name}</p>
        </header>

        {activeTab === 'dashboard' && <Dashboard letters={letters} users={users} />}

        {(activeTab === 'surat-masuk' || (currentUser.role === UserRole.ADMIN && activeTab === 'all-letters')) && (
          <LetterModule 
            type="INCOMING" 
            letters={letters.filter(l => l.type === 'INCOMING')} 
            onAdd={addLetter}
            onDelete={deleteLetter}
            onUpdate={updateLetter}
            canManage={currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.STAF_MASUK}
            userRole={currentUser.role}
          />
        )}

        {(activeTab === 'surat-keluar' || (currentUser.role === UserRole.ADMIN && activeTab === 'all-letters')) && (
          <LetterModule 
            type="OUTGOING" 
            letters={letters.filter(l => l.type === 'OUTGOING')} 
            onAdd={addLetter}
            onDelete={deleteLetter}
            onUpdate={updateLetter}
            canManage={currentUser.role === UserRole.ADMIN || currentUser.role === UserRole.STAF_KELUAR}
            userRole={currentUser.role}
          />
        )}

        {activeTab === 'users' && currentUser.role === UserRole.ADMIN && (
          <UserManagement 
            users={users} 
            onUpdateUsers={(updated) => setUsers(updated)} 
          />
        )}
      </main>
    </div>
  );
};

export default App;

