import React, { useState } from 'react';
import { Letter, LetterType, Disposition, UserRole, DispositionAssignment } from '../types';
import { analyzeLetter } from '../services/geminiService';

interface LetterModuleProps {
  type: LetterType;
  letters: Letter[];
  onAdd: (letter: Omit<Letter, 'id' | 'createdAt'>) => void;
  onDelete: (id: string) => void;
  onUpdate: (letter: Letter) => void;
  canManage: boolean;
  userRole?: UserRole;
}

const LetterModule: React.FC<LetterModuleProps> = ({ type, letters, onAdd, onDelete, onUpdate, canManage, userRole }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingLetter, setEditingLetter] = useState<Letter | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showDisposition, setShowDisposition] = useState(false);
  const [newRecipient, setNewRecipient] = useState('');

  const [formData, setFormData] = useState({
    referenceNumber: '',
    date: new Date().toISOString().split('T')[0],
    sender: '',
    subject: '',
    description: '',
    disposition: undefined as Disposition | undefined
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingLetter) {
      onUpdate({ ...editingLetter, ...formData });
      setEditingLetter(null);
    } else {
      onAdd({ ...formData, type });
    }
    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setFormData({
      referenceNumber: '',
      date: new Date().toISOString().split('T')[0],
      sender: '',
      subject: '',
      description: '',
      disposition: undefined
    });
    setNewRecipient('');
    setShowDisposition(false);
  };

  const handleEdit = (letter: Letter) => {
    setFormData({
      referenceNumber: letter.referenceNumber,
      date: letter.date,
      sender: letter.sender,
      subject: letter.subject,
      description: letter.description || '',
      disposition: letter.disposition
    });
    setShowDisposition(!!letter.disposition);
    setEditingLetter(letter);
    setShowForm(true);
  };

  const handleAnalyze = async () => {
    if (!formData.description) return alert("Masukkan isi surat terlebih dahulu untuk dianalisis.");
    setIsAnalyzing(true);
    const result = await analyzeLetter(formData.description);
    if (result) {
      setFormData(prev => ({
        ...prev,
        description: `Analisis AI:\nRingkasan: ${result.summary}\nKategori: ${result.category}\nPrioritas: ${result.priority}\n\nIsi Asli:\n${prev.description}`
      }));
    }
    setIsAnalyzing(false);
  };

  const addRecipient = () => {
    if (!newRecipient.trim()) return;
    const currentDisp = formData.disposition || { assignments: [], instruction: '', date: new Date().toISOString().split('T')[0] };
    const newAssignment: DispositionAssignment = { recipient: newRecipient.trim(), status: 'Menunggu' };

    setFormData({
      ...formData,
      disposition: {
        ...currentDisp,
        assignments: [...currentDisp.assignments, newAssignment]
      }
    });
    setNewRecipient('');
  };

  const removeRecipient = (index: number) => {
    if (!formData.disposition) return;
    const updatedAssignments = formData.disposition.assignments.filter((_, i) => i !== index);
    setFormData({
      ...formData,
      disposition: {
        ...formData.disposition,
        assignments: updatedAssignments
      }
    });
  };

  const updateAssignmentStatus = (index: number, status: DispositionAssignment['status']) => {
    if (!formData.disposition) return;
    const updatedAssignments = [...formData.disposition.assignments];
    updatedAssignments[index].status = status;
    setFormData({
      ...formData,
      disposition: {
        ...formData.disposition,
        assignments: updatedAssignments
      }
    });
  };

  const updateInstruction = (instruction: string) => {
    const currentDisp = formData.disposition || { assignments: [], instruction: '', date: new Date().toISOString().split('T')[0] };
    setFormData({
      ...formData,
      disposition: { ...currentDisp, instruction }
    });
  };

  const isAdmin = userRole === UserRole.ADMIN;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="relative flex-1 max-w-xs">
           <span className="absolute left-3 top-2.5 text-slate-400">🔍</span>
           <input 
            type="text" 
            placeholder="Cari surat..." 
            className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-sm shadow-sm"
           />
        </div>
        {canManage && (
          <button 
            onClick={() => { resetForm(); setShowForm(true); }}
            className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2"
          >
            <span>+</span> {type === 'INCOMING' ? 'Tambah Surat Masuk' : 'Tambah Surat Keluar'}
          </button>
        )}
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Tgl / No. Surat</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">{type === 'INCOMING' ? 'Pengirim' : 'Penerima'}</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Perihal</th>
                {type === 'INCOMING' && <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Disposisi</th>}
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {letters.length > 0 ? (
                letters.map(letter => (
                  <tr key={letter.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <p className="font-semibold text-slate-800">{new Date(letter.date).toLocaleDateString('id-ID')}</p>
                      <p className="text-xs text-slate-500 font-mono">{letter.referenceNumber}</p>
                    </td>
                    <td className="px-6 py-4 font-medium text-slate-700">{letter.sender}</td>
                    <td className="px-6 py-4">
                      <p className="text-slate-800 line-clamp-1">{letter.subject}</p>
                    </td>
                    {type === 'INCOMING' && (
                      <td className="px-6 py-4">
                        {letter.disposition && letter.disposition.assignments.length > 0 ? (
                          <div className="flex flex-col gap-1">
                            <span className="px-2 py-0.5 bg-amber-100 text-amber-700 text-[10px] font-bold rounded-md w-fit">
                              Diteruskan ke {letter.disposition.assignments.length} Pihak
                            </span>
                            <span className="text-[10px] text-slate-500 italic truncate max-w-[120px]">
                              {letter.disposition.assignments[0].recipient}...
                            </span>
                          </div>
                        ) : (
                          <span className="px-2 py-0.5 bg-slate-100 text-slate-400 text-[10px] font-bold rounded-md w-fit">Belum Ada</span>
                        )}
                      </td>
                    )}
                    <td className="px-6 py-4 text-right space-x-2 whitespace-nowrap">
                      {canManage && (
                        <>
                          <button onClick={() => handleEdit(letter)} className="text-indigo-600 hover:text-indigo-800 text-sm font-bold px-3 py-1 hover:bg-indigo-50 rounded-lg transition-colors">Edit</button>
                          <button onClick={() => onDelete(letter.id)} className="text-red-500 hover:text-red-700 text-sm font-bold px-3 py-1 hover:bg-red-50 rounded-lg transition-colors">Hapus</button>
                        </>
                      )}
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={type === 'INCOMING' ? 5 : 4} className="px-6 py-12 text-center text-slate-400">Belum ada data surat tersedia.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showForm && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white w-full max-w-4xl rounded-3xl shadow-2xl overflow-y-auto max-h-[95vh] animate-in fade-in zoom-in duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-indigo-50/50 sticky top-0 bg-white z-10">
              <h2 className="text-xl font-bold text-indigo-900">
                {editingLetter ? 'Ubah' : 'Tambah'} {type === 'INCOMING' ? 'Surat Masuk' : 'Surat Keluar'}
              </h2>
              <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-slate-600 p-2">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Nomor Surat</label>
                  <input 
                    required 
                    value={formData.referenceNumber} 
                    onChange={e => setFormData({...formData, referenceNumber: e.target.value})}
                    className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                    placeholder="Contoh: 001/SK/2023"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Tanggal Surat</label>
                  <input 
                    type="date" 
                    required 
                    value={formData.date} 
                    onChange={e => setFormData({...formData, date: e.target.value})}
                    className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">{type === 'INCOMING' ? 'Asal / Pengirim' : 'Tujuan / Penerima'}</label>
                <input 
                  required 
                  value={formData.sender} 
                  onChange={e => setFormData({...formData, sender: e.target.value})}
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  placeholder={type === 'INCOMING' ? "Instansi Pengirim" : "Instansi Penerima"}
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">Perihal</label>
                <input 
                  required 
                  value={formData.subject} 
                  onChange={e => setFormData({...formData, subject: e.target.value})}
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  placeholder="Ringkasan singkat perihal surat"
                />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between items-center">
                  <label className="text-sm font-bold text-slate-700">Isi / Ringkasan Surat</label>
                  <button 
                    type="button" 
                    onClick={handleAnalyze} 
                    disabled={isAnalyzing}
                    className="text-xs font-bold text-indigo-600 hover:text-indigo-800 disabled:opacity-50 flex items-center gap-1"
                  >
                    {isAnalyzing ? 'Menganalisis...' : '✨ Analisis AI'}
                  </button>
                </div>
                <textarea 
                  rows={3} 
                  value={formData.description} 
                  onChange={e => setFormData({...formData, description: e.target.value})}
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none" 
                  placeholder="Ketik isi atau ringkasan surat di sini..."
                />
              </div>

              {/* SECTION DISPOSISI (HANYA SURAT MASUK) */}
              {type === 'INCOMING' && (
                <div className="border-2 border-dashed border-amber-200 rounded-2xl p-6 bg-amber-50/20 space-y-6">
                  <div className="flex justify-between items-center">
                    <h3 className="text-md font-bold text-amber-900 flex items-center gap-2">
                      <span className="text-xl">📋</span> Lembar Disposisi Multi-Penerima
                    </h3>
                    {!showDisposition && (
                      <button 
                        type="button" 
                        onClick={() => setShowDisposition(true)}
                        className="text-xs font-bold text-white bg-amber-600 hover:bg-amber-700 px-3 py-1.5 rounded-lg transition-colors"
                      >
                        Aktifkan Disposisi
                      </button>
                    )}
                  </div>

                  {showDisposition && (
                    <div className="space-y-6 animate-in slide-in-from-top-2 duration-300">
                      {/* Form Tambah Penerima */}
                      {isAdmin && (
                        <div className="flex gap-2">
                          <input 
                            value={newRecipient}
                            onChange={e => setNewRecipient(e.target.value)}
                            onKeyPress={e => e.key === 'Enter' && (e.preventDefault(), addRecipient())}
                            className="flex-1 px-4 py-2 border border-amber-200 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none text-sm bg-white" 
                            placeholder="Ketik Nama/Jabatan Penerima..."
                          />
                          <button 
                            type="button" 
                            onClick={addRecipient}
                            className="bg-amber-600 text-white px-4 py-2 rounded-xl text-sm font-bold hover:bg-amber-700"
                          >
                            Tambah
                          </button>
                        </div>
                      )}

                      {/* List Penerima */}
                      <div className="space-y-2">
                        <label className="text-xs font-bold text-amber-800 uppercase tracking-wider">Diteruskan Kepada:</label>
                        <div className="bg-white border border-amber-100 rounded-xl divide-y divide-amber-50 overflow-hidden shadow-sm">
                          {formData.disposition?.assignments && formData.disposition.assignments.length > 0 ? (
                            formData.disposition.assignments.map((asgn, idx) => (
                              <div key={idx} className="flex items-center justify-between p-3">
                                <div className="flex items-center gap-3">
                                  <span className="w-6 h-6 bg-amber-100 text-amber-700 rounded-full flex items-center justify-center text-[10px] font-bold">
                                    {idx + 1}
                                  </span>
                                  <span className="text-sm font-medium text-slate-700">{asgn.recipient}</span>
                                </div>
                                <div className="flex items-center gap-3">
                                  <select 
                                    value={asgn.status}
                                    onChange={e => updateAssignmentStatus(idx, e.target.value as any)}
                                    className="text-xs border-none bg-amber-50 text-amber-800 rounded-lg px-2 py-1 focus:ring-0 cursor-pointer"
                                  >
                                    <option value="Menunggu">Menunggu</option>
                                    <option value="Proses">Proses</option>
                                    <option value="Selesai">Selesai</option>
                                  </select>
                                  {isAdmin && (
                                    <button 
                                      type="button" 
                                      onClick={() => removeRecipient(idx)}
                                      className="text-amber-200 hover:text-red-500 transition-colors p-1"
                                    >
                                      ✕
                                    </button>
                                  )}
                                </div>
                              </div>
                            ))
                          ) : (
                            <p className="p-4 text-center text-xs text-slate-400 italic">Belum ada penerima yang ditambahkan.</p>
                          )}
                        </div>
                      </div>

                      {/* Instruksi Pimpinan */}
                      <div className="space-y-2">
                        <label className="text-xs font-bold text-amber-800 uppercase tracking-wider">Instruksi Pimpinan:</label>
                        <textarea 
                          readOnly={!isAdmin}
                          rows={2} 
                          value={formData.disposition?.instruction || ''}
                          onChange={e => updateInstruction(e.target.value)}
                          className="w-full px-4 py-3 border border-amber-200 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none bg-white text-sm resize-none" 
                          placeholder="Masukkan instruksi khusus terkait surat ini..."
                        />
                      </div>

                      {!isAdmin && (
                        <p className="text-[10px] text-amber-600 bg-amber-50 p-2 rounded-lg border border-amber-100">
                          ℹ️ Hanya Administrator yang dapat menambah/menghapus penerima dan mengubah instruksi.
                        </p>
                      )}
                    </div>
                  )}
                </div>
              )}

              <div className="flex justify-end gap-3 pt-6 sticky bottom-0 bg-white py-4 border-t border-slate-100">
                <button type="button" onClick={() => setShowForm(false)} className="px-6 py-2.5 text-slate-500 font-bold hover:bg-slate-100 rounded-xl transition-colors">Batal</button>
                <button type="submit" className="px-8 py-2.5 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all">
                  {editingLetter ? 'Simpan Perubahan' : 'Simpan Surat'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

