  onAdd: (letter: Omit<Letter, 'id' | 'createdAt'>) => void;
  onDelete: (id: string) => void;
  onUpdate: (letter: Letter) => void;
  canManage: boolean;
  userRole?: UserRole;
}

const LetterModule: React.FC<LetterModuleProps> = ({ type, letters, onAdd, onDelete, onUpdate, canManage, userRole }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingLetter, setEditingLetter] = useState<Letter | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showDisposition, setShowDisposition] = useState(false);
  const [showScanner, setShowScanner] = useState(false);
  const [newRecipient, setNewRecipient] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState({
    referenceNumber: '',
    date: new Date().toISOString().split('T')[0],
    sender: '',
    subject: '',
    description: '',
    scannedImages: [] as string[],
    disposition: undefined as Disposition | undefined
  });

  // Added handleAnalyze function to process letter description with AI
  const handleAnalyze = async () => {
    if (!formData.description) {
      alert('Harap isi deskripsi surat untuk dianalisis.');
      return;
    }

    setIsAnalyzing(true);
    try {
      const result = await analyzeLetter(formData.description);
      if (result) {
        setFormData(prev => ({
          ...prev,
          description: `Ringkasan: ${result.summary}\nKategori: ${result.category}\nPrioritas: ${result.priority}\n\n${prev.description}`
        }));
      }
    } catch (error) {
      console.error("AI Analysis failed:", error);
      alert('Gagal menganalisis surat. Pastikan koneksi dan API Key tersedia.');
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingLetter) {
      onUpdate({ ...editingLetter, ...formData });
      setEditingLetter(null);
    } else {
      onAdd({ ...formData, type });
    }
    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setFormData({
      referenceNumber: '',
      date: new Date().toISOString().split('T')[0],
      sender: '',
      subject: '',
      description: '',
      scannedImages: [],
      disposition: undefined
    });
    setNewRecipient('');
    setShowDisposition(false);
  };

  const handleEdit = (letter: Letter) => {
    setFormData({
      referenceNumber: letter.referenceNumber,
      date: letter.date,
      sender: letter.sender,
      subject: letter.subject,
      description: letter.description || '',
      scannedImages: letter.scannedImages || [],
      disposition: letter.disposition
    });
    setShowDisposition(!!letter.disposition);
    setEditingLetter(letter);
    setShowForm(true);
  };

  const handlePrint = (letter: Letter) => {
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const dispositionHtml = letter.disposition ? `
      <div style="margin-top: 30px; border: 2px solid #000; padding: 15px;">
        <h3 style="text-align: center; margin-top: 0; text-decoration: underline;">LEMBAR DISPOSISI</h3>
        <table style="width: 100%; border-collapse: collapse; margin-top: 10px;">
          <tr style="border-bottom: 1px solid #000;">
            <td style="padding: 8px; font-weight: bold; width: 30%;">Instruksi Pimpinan:</td>
            <td style="padding: 8px;">${letter.disposition.instruction || '-'}</td>
          </tr>
        </table>
        <h4 style="margin-bottom: 5px;">Diteruskan Kepada:</h4>
        <table style="width: 100%; border-collapse: collapse; border: 1px solid #000;">
          <thead>
            <tr style="background: #f0f0f0;">
              <th style="border: 1px solid #000; padding: 5px;">No</th>
              <th style="border: 1px solid #000; padding: 5px;">Penerima / Jabatan</th>
              <th style="border: 1px solid #000; padding: 5px;">Paraf / Status</th>
            </tr>
          </thead>
          <tbody>
            ${letter.disposition.assignments.map((asgn, i) => `
              <tr>
                <td style="border: 1px solid #000; padding: 5px; text-align: center;">${i + 1}</td>
                <td style="border: 1px solid #000; padding: 5px;">${asgn.recipient}</td>
                <td style="border: 1px solid #000; padding: 5px; text-align: center;">[ ${asgn.status} ]</td>
              </tr>
            `).join('')}
          </tbody>
        </table>
      </div>
    ` : '';

    printWindow.document.write(`
      <html>
        <head>
          <title>Cetak Surat - ${letter.referenceNumber}</title>
          <style>
            body { font-family: 'Arial', sans-serif; padding: 40px; line-height: 1.6; }
            .header { text-align: center; border-bottom: 3px double #000; padding-bottom: 10px; margin-bottom: 20px; }
            .info-table { width: 100%; margin-bottom: 20px; }
            .info-table td { padding: 5px 0; vertical-align: top; }
            @media print { .no-print { display: none; } }
          </style>
        </head>
        <body>
          <div class="header">
            <h2 style="margin: 0;">INSTANSI PEMERINTAH REPUBLIK INDONESIA</h2>
            <p style="margin: 5px 0;">Jl. Administrasi Digital No. 1, Jakarta | Telp: (021) 123456</p>
          </div>
          <table class="info-table">
            <tr><td style="width: 150px;">Nomor Surat</td><td>: ${letter.referenceNumber}</td></tr>
            <tr><td>Tanggal</td><td>: ${new Date(letter.date).toLocaleDateString('id-ID')}</td></tr>
            <tr><td>Asal/Tujuan</td><td>: ${letter.sender}</td></tr>
            <tr><td>Perihal</td><td>: <strong>${letter.subject}</strong></td></tr>
          </table>
          <div style="margin-top: 20px;">
            <p><strong>Ringkasan Isi:</strong></p>
            <p style="text-align: justify;">${letter.description || 'Tidak ada ringkasan.'}</p>
          </div>
          ${dispositionHtml}
          <div style="margin-top: 50px; text-align: right;">
            <p>Dicetak pada: ${new Date().toLocaleString('id-ID')}</p>
            <br><br><br>
            <p>( __________________________ )</p>
            <p>Petugas Arsip</p>
          </div>
          <script>window.onload = function() { window.print(); window.close(); }</script>
        </body>
      </html>
    `);
    printWindow.document.close();
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setFormData(prev => ({
            ...prev,
            scannedImages: [...prev.scannedImages, reader.result as string]
          }));
        };
        reader.readAsDataURL(file);
      });
    }
  };

  const addRecipient = () => {
    if (!newRecipient.trim()) return;
    const currentDisp = formData.disposition || { assignments: [], instruction: '', date: new Date().toISOString().split('T')[0] };
    const newAssignment: DispositionAssignment = { recipient: newRecipient.trim(), status: 'Menunggu' };

    setFormData({
      ...formData,
      disposition: {
        ...currentDisp,
        assignments: [...currentDisp.assignments, newAssignment]
      }
    });
    setNewRecipient('');
  };

  const removeRecipient = (index: number) => {
    if (!formData.disposition) return;
    const updatedAssignments = formData.disposition.assignments.filter((_, i) => i !== index);
    setFormData({
      ...formData,
      disposition: {
        ...formData.disposition,
        assignments: updatedAssignments
      }
    });
  };

  const updateAssignmentStatus = (index: number, status: DispositionAssignment['status']) => {
    if (!formData.disposition) return;
    const updatedAssignments = [...formData.disposition.assignments];
    updatedAssignments[index].status = status;
    setFormData({
      ...formData,
      disposition: {
        ...formData.disposition,
        assignments: updatedAssignments
      }
    });
  };

  const updateInstruction = (instruction: string) => {
    const currentDisp = formData.disposition || { assignments: [], instruction: '', date: new Date().toISOString().split('T')[0] };
    setFormData({
      ...formData,
      disposition: { ...currentDisp, instruction }
    });
  };

  const handleCapture = (base64: string) => {
    setFormData(prev => ({
      ...prev,
      scannedImages: [...prev.scannedImages, base64]
    }));
    setShowScanner(false);
  };

  const removeImage = (idx: number) => {
    setFormData(prev => ({
      ...prev,
      scannedImages: prev.scannedImages.filter((_, i) => i !== idx)
    }));
  };

  const isAdmin = userRole === UserRole.ADMIN;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center no-print">
        <div className="relative flex-1 max-w-xs">
           <span className="absolute left-3 top-2.5 text-slate-400">🔍</span>
           <input 
            type="text" 
            placeholder="Cari surat..." 
            className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-sm shadow-sm"
           />
        </div>
        {canManage && (
          <button 
            onClick={() => { resetForm(); setShowForm(true); }}
            className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2"
          >
            <span>+</span> {type === 'INCOMING' ? 'Tambah Surat Masuk' : 'Tambah Surat Keluar'}
          </button>
        )}
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden no-print">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Tgl / No. Surat</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">{type === 'INCOMING' ? 'Pengirim' : 'Penerima'}</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Perihal</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Dokumen</th>
                {type === 'INCOMING' && <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Disposisi</th>}
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {letters.length > 0 ? (
                letters.map(letter => (
                  <tr key={letter.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-6 py-4">
                      <p className="font-semibold text-slate-800">{new Date(letter.date).toLocaleDateString('id-ID')}</p>
                      <p className="text-xs text-slate-500 font-mono">{letter.referenceNumber}</p>
                    </td>
                    <td className="px-6 py-4 font-medium text-slate-700">{letter.sender}</td>
                    <td className="px-6 py-4">
                      <p className="text-slate-800 line-clamp-1">{letter.subject}</p>
                    </td>
                    <td className="px-6 py-4">
                      {letter.scannedImages && letter.scannedImages.length > 0 ? (
                        <div className="flex -space-x-2">
                          {letter.scannedImages.slice(0, 3).map((img, i) => (
                            <img key={i} src={img} className="w-8 h-8 rounded-md border-2 border-white object-cover bg-slate-100 shadow-sm" />
                          ))}
                          {letter.scannedImages.length > 3 && (
                            <div className="w-8 h-8 rounded-md border-2 border-white bg-slate-200 text-[10px] font-bold flex items-center justify-center text-slate-600">
                              +{letter.scannedImages.length - 3}
                            </div>
                          )}
                        </div>
                      ) : (
                        <span className="text-[10px] text-slate-300 italic">No Doc</span>
                      )}
                    </td>
                    {type === 'INCOMING' && (
                      <td className="px-6 py-4">
                        {letter.disposition && letter.disposition.assignments.length > 0 ? (
                          <div className="flex flex-col gap-1">
                            <span className="px-2 py-0.5 bg-amber-100 text-amber-700 text-[10px] font-bold rounded-md w-fit">
                              {letter.disposition.assignments.length} Penerima
                            </span>
                          </div>
                        ) : (
                          <span className="px-2 py-0.5 bg-slate-100 text-slate-400 text-[10px] font-bold rounded-md w-fit">Belum Ada</span>
                        )}
                      </td>
                    )}
                    <td className="px-6 py-4 text-right space-x-1 whitespace-nowrap">
                      <button 
                        onClick={() => handlePrint(letter)} 
                        title="Cetak Surat & Disposisi"
                        className="text-slate-500 hover:text-indigo-600 p-1.5 hover:bg-indigo-50 rounded-lg transition-colors"
                      >
                        🖨️
                      </button>
                      {canManage && (
                        <>
                          <button onClick={() => handleEdit(letter)} className="text-indigo-600 hover:text-indigo-800 text-sm font-bold px-3 py-1 hover:bg-indigo-50 rounded-lg transition-colors">Edit</button>
                          <button onClick={() => onDelete(letter.id)} className="text-red-500 hover:text-red-700 text-sm font-bold px-3 py-1 hover:bg-red-50 rounded-lg transition-colors">Hapus</button>
                        </>
                      )}
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={type === 'INCOMING' ? 6 : 5} className="px-6 py-12 text-center text-slate-400">Belum ada data surat tersedia.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showForm && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm flex items-center justify-center z-50 p-4 no-print">
          <div className="bg-white w-full max-w-4xl rounded-3xl shadow-2xl overflow-y-auto max-h-[95vh] animate-in fade-in zoom-in duration-200 border border-slate-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-indigo-50/50 sticky top-0 bg-white z-10">
              <div className="flex items-center gap-3">
                <span className="text-2xl">{editingLetter ? '📝' : '📥'}</span>
                <h2 className="text-xl font-bold text-indigo-900">
                  {editingLetter ? 'Ubah' : 'Tambah'} {type === 'INCOMING' ? 'Surat Masuk' : 'Surat Keluar'}
                </h2>
              </div>
              <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-slate-600 p-2">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Nomor Surat</label>
                  <input 
                    required 
                    value={formData.referenceNumber} 
                    onChange={e => setFormData({...formData, referenceNumber: e.target.value})}
                    className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                    placeholder="Contoh: 001/SK/2023"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Tanggal Surat</label>
                  <input 
                    type="date" 
                    required 
                    value={formData.date} 
                    onChange={e => setFormData({...formData, date: e.target.value})}
                    className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">{type === 'INCOMING' ? 'Asal / Pengirim' : 'Tujuan / Penerima'}</label>
                <input 
                  required 
                  value={formData.sender} 
                  onChange={e => setFormData({...formData, sender: e.target.value})}
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  placeholder={type === 'INCOMING' ? "Instansi Pengirim" : "Instansi Penerima"}
                />
              </div>

              {/* DOKUMEN SCAN SECTION */}
              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <label className="text-sm font-bold text-slate-700">Dokumen Fisik (Scan Printer/Kamera)</label>
                  <div className="flex gap-2">
                    <input 
                      type="file" 
                      ref={fileInputRef} 
                      className="hidden" 
                      multiple 
                      accept="image/*,application/pdf" 
                      onChange={handleFileUpload}
                    />
                    <button 
                      type="button" 
                      onClick={() => fileInputRef.current?.click()}
                      className="text-xs font-bold text-slate-600 hover:text-slate-800 flex items-center gap-1 bg-white px-3 py-1.5 rounded-lg border border-slate-200 shadow-sm"
                    >
                      📁 Unggah File Scan
                    </button>
                    <button 
                      type="button" 
                      onClick={() => setShowScanner(true)}
                      className="text-xs font-bold text-indigo-600 hover:text-indigo-800 flex items-center gap-1 bg-indigo-50 px-3 py-1.5 rounded-lg border border-indigo-100 shadow-sm"
                    >
                      📸 Ambil Foto Kamera
                    </button>
                  </div>
                </div>

                <div className="flex flex-wrap gap-4 p-4 bg-slate-50 border border-dashed border-slate-200 rounded-2xl min-h-[120px] transition-all">
                  {formData.scannedImages.length > 0 ? (
                    formData.scannedImages.map((img, idx) => (
                      <div key={idx} className="relative group w-24 h-32 rounded-lg overflow-hidden shadow-md border-2 border-white">
                        <img src={img} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                        <button 
                          type="button"
                          onClick={() => removeImage(idx)}
                          className="absolute top-1 right-1 w-6 h-6 bg-red-500 text-white rounded-full flex items-center justify-center text-xs opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
                        >
                          ✕
                        </button>
                        <div className="absolute bottom-0 inset-x-0 bg-black/60 text-[10px] text-white text-center py-1 font-bold">HALAMAN ${idx+1}</div>
                      </div>
                    ))
                  ) : (
                    <div className="w-full flex flex-col items-center justify-center text-slate-400 py-6">
                      <span className="text-3xl mb-2">📄</span>
                      <p className="text-xs font-semibold uppercase tracking-widest text-slate-400">Belum ada lampiran hasil scan</p>
                      <p className="text-[10px] text-slate-300 mt-1">Silakan ambil gambar atau unggah file dari scanner</p>
                    </div>
                  )}
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">Perihal</label>
                <input 
                  required 
                  value={formData.subject} 
                  onChange={e => setFormData({...formData, subject: e.target.value})}
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none font-semibold text-slate-800" 
                  placeholder="Ringkasan singkat perihal surat"
                />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between items-center">
                  <label className="text-sm font-bold text-slate-700">Isi / Ringkasan Surat</label>
                  <button 
                    type="button" 
                    onClick={handleAnalyze} 
                    disabled={isAnalyzing}
                    className="text-xs font-bold text-indigo-600 hover:text-indigo-800 disabled:opacity-50 flex items-center gap-1"
                  >
                    {isAnalyzing ? 'Menganalisis...' : '✨ Analisis AI'}
                  </button>
                </div>
                <textarea 
                  rows={3} 
                  value={formData.description} 
                  onChange={e => setFormData({...formData, description: e.target.value})}
                  className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none bg-slate-50/50" 
                  placeholder="Ketik isi atau ringkasan surat di sini..."
                />
              </div>

              {type === 'INCOMING' && (
                <div className="border-2 border-dashed border-amber-200 rounded-2xl p-6 bg-amber-50/20 space-y-6">
                  <div className="flex justify-between items-center">
                    <h3 className="text-md font-bold text-amber-900 flex items-center gap-2">
                      <span className="text-xl">📋</span> Lembar Disposisi Digital
                    </h3>
                    {!showDisposition && (
                      <button 
                        type="button" 
                        onClick={() => setShowDisposition(true)}
                        className="text-xs font-bold text-white bg-amber-600 hover:bg-amber-700 px-4 py-2 rounded-xl transition-all shadow-md shadow-amber-100"
                      >
                        Buat Lembar Disposisi
                      </button>
                    )}
                  </div>

                  {showDisposition && (
                    <div className="space-y-6 animate-in slide-in-from-top-2 duration-300">
                      {isAdmin && (
                        <div className="flex gap-2">
                          <input 
                            value={newRecipient}
                            onChange={e => setNewRecipient(e.target.value)}
                            onKeyPress={e => e.key === 'Enter' && (e.preventDefault(), addRecipient())}
                            className="flex-1 px-4 py-2 border border-amber-200 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none text-sm bg-white" 
                            placeholder="Ketik Nama/Jabatan Penerima..."
                          />
                          <button 
                            type="button" 
                            onClick={addRecipient}
                            className="bg-amber-600 text-white px-5 py-2 rounded-xl text-sm font-bold hover:bg-amber-700 shadow-sm"
                          >
                            Tambah
                          </button>
                        </div>
                      )}

                      <div className="space-y-2">
                        <label className="text-xs font-bold text-amber-800 uppercase tracking-wider">Pihak Terkait (Penerima Disposisi):</label>
                        <div className="bg-white border border-amber-100 rounded-xl divide-y divide-amber-50 overflow-hidden shadow-sm">
                          {formData.disposition?.assignments && formData.disposition.assignments.length > 0 ? (
                            formData.disposition.assignments.map((asgn, idx) => (
                              <div key={idx} className="flex items-center justify-between p-3 hover:bg-amber-50/30 transition-colors">
                                <div className="flex items-center gap-3">
                                  <span className="w-6 h-6 bg-amber-100 text-amber-700 rounded-full flex items-center justify-center text-[10px] font-bold">
                                    {idx + 1}
                                  </span>
                                  <span className="text-sm font-medium text-slate-700">{asgn.recipient}</span>
                                </div>
                                <div className="flex items-center gap-3">
                                  <select 
                                    value={asgn.status}
                                    onChange={e => updateAssignmentStatus(idx, e.target.value as any)}
                                    className="text-xs border-none bg-amber-50 text-amber-800 rounded-lg px-2 py-1 focus:ring-0 cursor-pointer font-bold"
                                  >
                                    <option value="Menunggu">Menunggu</option>
                                    <option value="Proses">Proses</option>
                                    <option value="Selesai">Selesai</option>
                                  </select>
                                  {isAdmin && (
                                    <button type="button" onClick={() => removeRecipient(idx)} className="text-amber-200 hover:text-red-500 transition-colors p-1" title="Hapus">✕</button>
                                  )}
                                </div>
                              </div>
                            ))
                          ) : (
                            <p className="p-4 text-center text-xs text-slate-400 italic">Klik tambah untuk menentukan penerima instruksi.</p>
                          )}
                        </div>
                      </div>

                      <div className="space-y-2">
                        <label className="text-xs font-bold text-amber-800 uppercase tracking-wider">Instruksi Khusus Pimpinan:</label>
                        <textarea 
                          readOnly={!isAdmin}
                          rows={2} 
                          value={formData.disposition?.instruction || ''}
                          onChange={e => updateInstruction(e.target.value)}
                          className="w-full px-4 py-3 border border-amber-200 rounded-xl focus:ring-2 focus:ring-amber-500 outline-none bg-white text-sm resize-none shadow-sm" 
                          placeholder="Contoh: Segera tindak lanjuti dan laporkan hasilnya."
                        />
                      </div>
                    </div>
                  )}
                </div>
              )}

              <div className="flex justify-between items-center pt-6 sticky bottom-0 bg-white py-4 border-t border-slate-100">
                <div className="text-slate-400 text-[10px] flex items-center gap-2">
                   <span className="flex w-2 h-2 rounded-full bg-emerald-500"></span>
                   Auto-save Draft Enabled
                </div>
                <div className="flex gap-3">
                  <button type="button" onClick={() => setShowForm(false)} className="px-6 py-2.5 text-slate-500 font-bold hover:bg-slate-100 rounded-xl transition-colors">Batal</button>
                  <button type="submit" className="px-8 py-2.5 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg shadow-indigo-200 transition-all flex items-center gap-2">
                    {editingLetter ? '💾 Simpan Perubahan' : '➕ Simpan Surat & Arsip'}
                  </button>
                </div>
              </div>
            </form>
          </div>
        </div>
      )}

      {showScanner && (
        <Scanner 
          onCapture={handleCapture}
          onClose={() => setShowScanner(false)}
        />
      )}
    </div>
  );
};

export default LetterModule;

import React, { useRef, useState, useEffect } from 'react';

interface ScannerProps {
  onComplete: (images: string[]) => void;
  onClose: () => void;
}

const Scanner: React.FC<ScannerProps> = ({ onComplete, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [capturedImages, setCapturedImages] = useState<string[]>([]);
  const [flash, setFlash] = useState(false);

  useEffect(() => {
    async function startCamera() {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({ 
          video: { 
            facingMode: 'environment',
            width: { ideal: 1920 },
            height: { ideal: 1080 }
          } 
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
        }
      } catch (err) {
        setError('Gagal mengakses kamera. Pastikan izin kamera telah diberikan.');
        console.error(err);
      }
    }
    startCamera();
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      setFlash(true);
      setTimeout(() => setFlash(false), 150);

      const video = videoRef.current;
      const canvas = canvasRef.current;

      // Use higher resolution for capture
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;

      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
        setCapturedImages(prev => [...prev, dataUrl]);
      }
    }
  };

  const removeCaptured = (index: number) => {
    setCapturedImages(prev => prev.filter((_, i) => i !== index));
  };

  return (
    <div className="fixed inset-0 bg-slate-950 z-[100] flex flex-col items-center justify-between p-4 sm:p-8">
      {/* Header Info */}
      <div className="w-full flex justify-between items-center text-white z-10">
        <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
          <span className="text-2xl">✕</span>
        </button>
        <div className="text-center">
          <p className="font-bold text-lg">Scan Dokumen</p>
          <p className="text-xs text-slate-400">{capturedImages.length} Halaman Terambil</p>
        </div>
        <button 
          onClick={() => onComplete(capturedImages)} 
          disabled={capturedImages.length === 0}
          className="bg-indigo-600 disabled:bg-slate-800 disabled:text-slate-500 text-white px-6 py-2 rounded-xl font-bold transition-all shadow-lg active:scale-95"
        >
          Selesai
        </button>
      </div>

      {/* Viewfinder Container */}
      <div className="relative w-full max-w-lg aspect-[3/4] bg-black rounded-[2rem] overflow-hidden shadow-2xl border-4 border-slate-800 my-4">
        {error ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center text-white p-6 text-center">
            <span className="text-4xl mb-4">⚠️</span>
            <p className="font-bold">{error}</p>
            <button onClick={onClose} className="mt-6 px-6 py-2 bg-white text-black rounded-xl font-bold">Tutup</button>
          </div>
        ) : (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              className={`w-full h-full object-cover transition-opacity duration-300 ${flash ? 'opacity-30' : 'opacity-100'}`}
            />
            {/* Viewfinder Overlay */}
            <div className="absolute inset-8 border-2 border-white/20 rounded-lg pointer-events-none">
                <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-indigo-500/50"></div>
                <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-indigo-500/50"></div>
                <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-indigo-500/50"></div>
                <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-indigo-500/50"></div>
            </div>
            {flash && <div className="absolute inset-0 bg-white animate-pulse"></div>}
          </>
        )}
      </div>

      {/* Captured Gallery */}
      <div className="w-full max-w-2xl h-24 flex gap-3 overflow-x-auto pb-2 px-2 scrollbar-hide no-scrollbar">
        {capturedImages.map((img, idx) => (
          <div key={idx} className="relative flex-shrink-0 w-16 h-20 rounded-lg border-2 border-white/20 overflow-hidden group">
            <img src={img} className="w-full h-full object-cover" />
            <button 
              onClick={() => removeCaptured(idx)}
              className="absolute top-0 right-0 bg-red-500 text-white text-[10px] w-4 h-4 rounded-bl-lg flex items-center justify-center"
            >
              ✕
            </button>
            <div className="absolute bottom-0 inset-x-0 bg-black/40 text-[8px] text-white text-center font-bold">{idx + 1}</div>
          </div>
        ))}
        {capturedImages.length === 0 && (
          <div className="w-full flex items-center justify-center text-slate-600 text-sm italic">
            Ambil foto dokumen untuk melihat pratinjau halaman
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="pb-4 flex flex-col items-center gap-4">
        <button 
          onClick={takePhoto}
          className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center p-1.5 hover:scale-105 active:scale-90 transition-all shadow-xl shadow-indigo-900/20"
        >
          <div className="w-full h-full bg-white rounded-full flex items-center justify-center">
            <span className="text-2xl">📸</span>
          </div>
        </button>
        <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Ketuk untuk mengambil halaman</p>
      </div>

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default Scanner;

import React, { useState, useRef } from 'react';
import { Letter, LetterType, Disposition, UserRole, DispositionAssignment } from '../types';
import { analyzeLetter } from '../services/geminiService';
import Scanner from './Scanner';

interface LetterModuleProps {
  type: LetterType;
  letters: Letter[];
  onAdd: (letter: Omit<Letter, 'id' | 'createdAt'>) => void;
  onDelete: (id: string) => void;
  onUpdate: (letter: Letter) => void;
  canManage: boolean;
  userRole?: UserRole;
}

const LetterModule: React.FC<LetterModuleProps> = ({ type, letters, onAdd, onDelete, onUpdate, canManage, userRole }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingLetter, setEditingLetter] = useState<Letter | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showDisposition, setShowDisposition] = useState(false);
  const [showScanner, setShowScanner] = useState(false);
  const [newRecipient, setNewRecipient] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState({
    referenceNumber: '',
    date: new Date().toISOString().split('T')[0],
    sender: '',
    subject: '',
    description: '',
    scannedImages: [] as string[],
    disposition: undefined as Disposition | undefined
  });

  const handleAnalyze = async () => {
    if (!formData.description) {
      alert('Harap isi deskripsi surat untuk dianalisis.');
      return;
    }

    setIsAnalyzing(true);
    try {
      const result = await analyzeLetter(formData.description);
      if (result) {
        setFormData(prev => ({
          ...prev,
          description: `Analisis AI:\nRingkasan: ${result.summary}\nKategori: ${result.category}\nPrioritas: ${result.priority}\n\n${prev.description}`
        }));
      }
    } catch (error) {
      console.error("AI Analysis failed:", error);
      alert('Gagal menganalisis surat.');
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingLetter) {
      onUpdate({ ...editingLetter, ...formData });
      setEditingLetter(null);
    } else {
      onAdd({ ...formData, type });
    }
    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setFormData({
      referenceNumber: '',
      date: new Date().toISOString().split('T')[0],
      sender: '',
      subject: '',
      description: '',
      scannedImages: [],
      disposition: undefined
    });
