    } else {
      updatedAgendas = [{ ...formData, id: Math.random().toString(36).substr(2, 9), createdAt: Date.now() }, ...agendas];
    }
    onSave(updatedAgendas);
    setShowForm(false);
    resetForm();
  };

  const resetForm = () => {
    setFormData({
      id: '',
      dayDate: '',
      items: [],
      signedBy: 'Novi Haryanto, S. Adm',
      signedNip: '197111201991031003',
