        </body>
      </html>
    `);
    printWindow.document.close();
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      // Fix: Explicitly cast Array.from(files) to File[] to resolve 'unknown' type issues in strict mode
      (Array.from(files) as File[]).forEach(file => {
        const isValidType = file.type.startsWith('image/') || file.type === 'application/pdf';
        if (!isValidType) {
          alert(`File ${file.name} tidak didukung. Gunakan JPG/PNG atau PDF.`);
          return;
        }

        const reader = new FileReader();
        reader.onloadend = () => {
          setFormData(prev => ({
            ...prev,
            scannedImages: [...prev.scannedImages, reader.result as string]
          }));
        };
        reader.readAsDataURL(file);
      });
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removeImage = (idx: number) => {
    setFormData(prev => ({
      ...prev,
      scannedImages: prev.scannedImages.filter((_, i) => i !== idx)
