import { GoogleGenAI, Type } from "@google/genai";

// Inisialisasi secara aman
const getAIInstance = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey || apiKey === "undefined") {
    console.warn("API_KEY is missing. AI features will be disabled.");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const analyzeLetter = async (text: string) => {
  if (!text) return null;

  const ai = getAIInstance();
  if (!ai) return null;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this letter text and extract key information in Indonesian: ${text}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "Ringkasan singkat surat" },
            category: { type: Type.STRING, description: "Kategori surat (e.g., Undangan, Pemberitahuan, Izin)" },
            priority: { type: Type.STRING, description: "Tingkat kepentingan (Tinggi, Sedang, Rendah)" }
          },
          required: ["summary", "category", "priority"]
        }
      }
    });

    return JSON.parse(response.text.trim());
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return null;
  }
};

import React, { useState, useMemo } from 'react';
import { Agenda, AgendaItem } from '../types';

interface AgendaModuleProps {
  agendas: Agenda[];
  onSave: (agendas: Agenda[]) => void;
  canManage: boolean;
}

const AgendaModule: React.FC<AgendaModuleProps> = ({ agendas, onSave, canManage }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingAgenda, setEditingAgenda] = useState<Agenda | null>(null);
  const [rawDate, setRawDate] = useState(''); // To hold YYYY-MM-DD from input[type="date"]

  const [formData, setFormData] = useState<Agenda>({
    id: '',
    dayDate: '',
    items: [],
    signedBy: 'Novi Haryanto, S. Adm',
    signedNip: '197111201991031003',
    createdAt: 0
  });

  const [newItem, setNewItem] = useState<Omit<AgendaItem, 'id'>>({
    time: '',
    location: '',
    event: '',
    dressCode: 'Menyesuaikan',
    remarks: ''
  });

  const formatIndonesianDate = (dateStr: string) => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    const days = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', "Jum'at", 'Sabtu'];
    const dayName = days[date.getDay()];

    const formatter = new Intl.DateTimeFormat('id-ID', {
      day: 'numeric',
      month: 'long',
      year: 'numeric'
    });

    return `${dayName}/ ${formatter.format(date)}`;
  };

  const handleDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setRawDate(value);
    setFormData(prev => ({
      ...prev,
      dayDate: formatIndonesianDate(value)
    }));
