                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  placeholder="Password akses"
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">Role Pengguna</label>
                <select 
                  value={formData.role} 
                  onChange={e => setFormData({...formData, role: e.target.value as UserRole})}
                  className="w-full px-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                >
                  <option value={UserRole.ADMIN}>Admin</option>
                  <option value={UserRole.STAF_MASUK}>Staf Surat Masuk</option>
                  <option value={UserRole.STAF_KELUAR}>Staf Surat Keluar</option>
                </select>
