                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">{type === 'INCOMING' ? 'Pengirim (Instansi/Personal)' : 'Penerima / Tujuan'}</label>
                <input 
                  required 
                  value={formData.sender} 
