                    </button>
                    <button 
                      type="button" 
                      onClick={() => setShowScanner(true)}
                      className="text-xs font-bold text-slate-600 hover:bg-slate-50 flex items-center gap-1 bg-white px-3 py-1.5 rounded-lg border border-slate-200 shadow-sm transition-colors"
                    >
