import React, { useState, useMemo } from 'react';
import { Agenda, AgendaItem } from '../types';

interface AgendaModuleProps {
  agendas: Agenda[];
  onSave: (agendas: Agenda[]) => void;
  canManage: boolean;
}

const AgendaModule: React.FC<AgendaModuleProps> = ({ agendas, onSave, canManage }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingAgenda, setEditingAgenda] = useState<Agenda | null>(null);
  const [rawDate, setRawDate] = useState('');
  const [editingItemIndex, setEditingItemIndex] = useState<number | null>(null);

  const [formData, setFormData] = useState<Agenda>({
    id: '',
    dayDate: '',
    items: [],
    signedBy: 'Novi Haryanto, S. Adm',
    signedNip: '197111201991031003',
    createdAt: 0
  });

  const [newItem, setNewItem] = useState<Omit<AgendaItem, 'id'>>({
    time: '',
    location: '',
    event: '',
    dressCode: 'Menyesuaikan',
    remarks: ''
  });

  const formatIndonesianDate = (dateStr: string) => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    const days = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', "Jum'at", 'Sabtu'];
    const dayName = days[date.getDay()];

    const formatter = new Intl.DateTimeFormat('id-ID', {
      day: 'numeric',
      month: 'long',
      year: 'numeric'
    });

    return `${dayName}/ ${formatter.format(date)}`;
  };

  const handleDateChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setRawDate(value);
    setFormData(prev => ({
      ...prev,
      dayDate: formatIndonesianDate(value)
    }));
  };

  const handleAddItem = () => {
    if (!newItem.event) return;

    if (editingItemIndex !== null) {
      const updatedItems = [...formData.items];
      updatedItems[editingItemIndex] = {
        ...newItem,
        id: formData.items[editingItemIndex].id
      };
      setFormData(prev => ({ ...prev, items: updatedItems }));
      setEditingItemIndex(null);
    } else {
      const item: AgendaItem = {
        ...newItem,
        id: Math.random().toString(36).substr(2, 9)
      };
      setFormData(prev => ({ ...prev, items: [...prev.items, item] }));
    }

    setNewItem({
      time: '',
      location: '',
      event: '',
      dressCode: 'Menyesuaikan',
      remarks: ''
    });
  };

  const handleEditItemRequest = (index: number) => {
    const itemToEdit = formData.items[index];
    setNewItem({
      time: itemToEdit.time,
      location: itemToEdit.location,
      event: itemToEdit.event,
      dressCode: itemToEdit.dressCode,
      remarks: itemToEdit.remarks
    });
    setEditingItemIndex(index);
    document.getElementById('item-form-anchor')?.scrollIntoView({ behavior: 'smooth' });
  };

  const cancelEditItem = () => {
    setEditingItemIndex(null);
    setNewItem({
      time: '',
      location: '',
      event: '',
      dressCode: 'Menyesuaikan',
      remarks: ''
    });
  };

  const handleRemoveItem = (id: string) => {
    setFormData(prev => ({ ...prev, items: prev.items.filter(i => i.id !== id) }));
    if (editingItemIndex !== null) setEditingItemIndex(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    let updatedAgendas;
    if (editingAgenda) {
      updatedAgendas = agendas.map(a => a.id === editingAgenda.id ? { ...formData } : a);
    } else {
      updatedAgendas = [{ ...formData, id: Math.random().toString(36).substr(2, 9), createdAt: Date.now() }, ...agendas];
    }
    onSave(updatedAgendas);
    setShowForm(false);
    resetForm();
  };

  const resetForm = () => {
    setFormData({
      id: '',
      dayDate: '',
      items: [],
      signedBy: 'Novi Haryanto, S. Adm',
      signedNip: '197111201991031003',
      createdAt: 0
    });
    setRawDate('');
    setEditingAgenda(null);
    setEditingItemIndex(null);
  };

  const handleEdit = (agenda: Agenda) => {
    setFormData(agenda);
    setEditingAgenda(agenda);
    setShowForm(true);
  };

  const handleDelete = (id: string) => {
    if (confirm('Hapus agenda ini?')) {
      onSave(agendas.filter(a => a.id !== id));
    }
  };

  const handlePrint = (agenda: Agenda) => {
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const rows = agenda.items.map((item, idx) => {
      const remarksList = item.remarks.split('\n').filter(r => r.trim()).map(r => `<li>${r}</li>`).join('');
      return `
        <tr>
          ${idx === 0 ? `<td rowspan="${agenda.items.length}" style="border: 1px solid black; padding: 10px; vertical-align: top; text-align: center; font-weight: bold;">${agenda.dayDate}</td>` : ''}
          <td style="border: 1px solid black; padding: 10px; text-align: center;">${item.time}</td>
          <td style="border: 1px solid black; padding: 10px;">${item.location}</td>
          <td style="border: 1px solid black; padding: 10px;">${item.event}</td>
          <td style="border: 1px solid black; padding: 10px; text-align: center;">${item.dressCode}</td>
          <td style="border: 1px solid black; padding: 10px;">
            <ul style="margin: 0; padding-left: 20px;">${remarksList}</ul>
          </td>
        </tr>
      `;
    }).join('');

    printWindow.document.write(`
      <html>
        <head>
          <title>Agenda Kepala Dinas</title>
          <style>
            @page { size: landscape; margin: 1cm; }
            body { font-family: 'Arial', sans-serif; margin: 0; padding: 20px; color: #000; }
            .header { text-align: center; margin-bottom: 30px; }
            .header h2 { margin: 0; font-size: 18px; text-transform: uppercase; }
            table { width: 100%; border-collapse: collapse; margin-top: 20px; font-size: 12px; }
            th { border: 1px solid black; padding: 8px; background: #f0f0f0; text-transform: uppercase; }
            .footer { margin-top: 40px; margin-left: 70%; text-align: center; }
            .signature-box { margin-top: 60px; font-weight: bold; text-decoration: underline; }
          </style>
        </head>
        <body>
          <div class="header">
            <h2>AGENDA KEPALA DINAS</h2>
            <h2>PROVINSI NUSA TENGGARA BARAT</h2>
          </div>
          <table>
            <thead>
              <tr>
                <th style="width: 15%;">HARI/TANGGAL</th>
                <th style="width: 10%;">WAKTU</th>
                <th style="width: 15%;">TEMPAT</th>
                <th style="width: 30%;">ACARA/KEGIATAN</th>
                <th style="width: 15%;">PAKAIAN</th>
                <th style="width: 15%;">KETERANGAN</th>
              </tr>
            </thead>
            <tbody>
              ${rows}
            </tbody>
          </table>
          <div class="footer">
            <p>Mengetahui,</p>
            <p>Kepala Sub Bagian Umum</p>
            <div class="signature-box">${agenda.signedBy}</div>
            <p style="margin-top: 5px;">${agenda.signedNip}</p>
            <p style="font-size: 8px; margin-top: 20px;">Operator: ${agenda.createdBy || 'Sistem'}</p>
          </div>
          <script>window.onload = () => { window.print(); window.close(); }</script>
        </body>
      </html>
    `);
    printWindow.document.close();
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center no-print">
        <h2 className="text-xl font-bold text-slate-800">Daftar Agenda Kegiatan</h2>
        {canManage && (
          <button 
            onClick={() => { resetForm(); setShowForm(true); }}
            className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2 rounded-xl font-bold transition-all shadow-md"
          >
            + Buat Agenda Baru
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 no-print">
        {agendas.length > 0 ? agendas.map(agenda => (
          <div key={agenda.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 space-y-4 hover:shadow-md transition-shadow relative overflow-hidden">
            <div className="flex justify-between items-start relative z-10">
              <div>
                <p className="text-indigo-600 font-bold">{agenda.dayDate}</p>
                <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{agenda.items.length} Kegiatan</p>
              </div>
              <span className="text-xs font-bold text-indigo-400/50">#{agenda.id.substr(0,4)}</span>
            </div>
            <div className="space-y-2 border-t pt-3 relative z-10">
               {agenda.items.slice(0, 2).map(item => (
                 <p key={item.id} className="text-sm text-slate-600 truncate">• {item.time} - {item.event}</p>
               ))}
               {agenda.items.length > 2 && <p className="text-xs text-slate-400 italic">+{agenda.items.length - 2} lainnya...</p>}
            </div>

            <div className="pt-2 border-t flex flex-col gap-3">
              <p className="text-[10px] text-slate-400">👤 Diinput: <span className="font-bold text-indigo-500">{agenda.createdBy || 'Sistem'}</span></p>
              <div className="flex gap-2">
                <button 
                  onClick={() => handlePrint(agenda)}
                  title="Cetak/Preview"
                  className="flex-1 bg-slate-50 hover:bg-indigo-50 text-slate-500 hover:text-indigo-600 py-2 rounded-lg font-bold text-xs border border-slate-100 transition-colors"
                >
                  🖨️ Pratinjau
                </button>
                {canManage && (
                  <>
                    <button onClick={() => handleEdit(agenda)} className="bg-white border border-slate-100 text-indigo-600 p-2 rounded-lg text-xs hover:bg-indigo-50">✏️</button>
                    <button onClick={() => handleDelete(agenda.id)} className="bg-white border border-slate-100 text-red-500 p-2 rounded-lg text-xs hover:bg-red-50">🗑️</button>
                  </>
                )}
              </div>
            </div>
          </div>
        )) : (
          <div className="col-span-full py-12 text-center text-slate-400 bg-white rounded-2xl border border-dashed border-slate-200">
            Belum ada agenda kegiatan.
          </div>
        )}
      </div>

      {showForm && (
        <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm flex justify-center z-50 p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-4xl rounded-3xl shadow-2xl my-auto animate-in fade-in zoom-in duration-200 flex flex-col max-h-[95vh]">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-20 rounded-t-3xl">
              <h3 className="text-xl font-bold text-slate-800">{editingAgenda ? 'Edit' : 'Buat'} Agenda Harian</h3>
              <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-slate-600 p-2">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Pilih Tanggal</label>
                  <input 
                    type="date"
                    required 
                    value={rawDate} 
                    onChange={handleDateChange}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500" 
                  />
                  {formData.dayDate && <p className="text-[10px] font-bold text-indigo-500">{formData.dayDate}</p>}
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Penandatangan</label>
                  <input 
                    required 
                    value={formData.signedBy} 
                    onChange={e => setFormData({...formData, signedBy: e.target.value})}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                  />
                </div>
              </div>

              <div id="item-form-anchor" className={`${editingItemIndex !== null ? 'bg-indigo-50 border-indigo-200' : 'bg-slate-50 border-slate-100'} p-6 rounded-2xl space-y-4 border transition-colors duration-300`}>
                <div className="flex justify-between items-center">
                  <h4 className={`font-bold ${editingItemIndex !== null ? 'text-indigo-700' : 'text-slate-700'} text-sm uppercase`}>
                    {editingItemIndex !== null ? '📝 Edit Item' : 'Tambah Item'}
                  </h4>
                  {editingItemIndex !== null && <button type="button" onClick={cancelEditItem} className="text-xs font-bold text-red-500">Batal</button>}
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <input placeholder="Waktu" value={newItem.time} onChange={e => setNewItem({...newItem, time: e.target.value})} className="px-4 py-2 border rounded-lg text-sm outline-none" />
                  <input placeholder="Tempat" value={newItem.location} onChange={e => setNewItem({...newItem, location: e.target.value})} className="px-4 py-2 border rounded-lg text-sm outline-none" />
                  <input placeholder="Pakaian" value={newItem.dressCode} onChange={e => setNewItem({...newItem, dressCode: e.target.value})} className="px-4 py-2 border rounded-lg text-sm outline-none" />
                </div>
                <textarea placeholder="Acara / Kegiatan" value={newItem.event} onChange={e => setNewItem({...newItem, event: e.target.value})} className="w-full px-4 py-2 border rounded-lg text-sm outline-none resize-none" rows={2} />
                <textarea placeholder="Peserta / Keterangan" value={newItem.remarks} onChange={e => setNewItem({...newItem, remarks: e.target.value})} className="w-full px-4 py-2 border rounded-lg text-sm outline-none resize-none" rows={2} />
                <button type="button" onClick={handleAddItem} className={`w-full py-2.5 ${editingItemIndex !== null ? 'bg-amber-500' : 'bg-indigo-600'} text-white rounded-lg font-bold text-sm transition-all`}>
                  {editingItemIndex !== null ? 'Simpan Item' : '+ Tambah ke Daftar'}
                </button>
              </div>

              <div className="space-y-3">
                <table className="w-full text-left text-sm border-collapse">
                  <thead className="bg-slate-50">
                    <tr>
                      <th className="p-3 border text-xs font-bold uppercase text-slate-400">Waktu</th>
                      <th className="p-3 border text-xs font-bold uppercase text-slate-400">Acara</th>
                      <th className="p-3 border text-xs font-bold uppercase text-slate-400 text-right">Aksi</th>
                    </tr>
                  </thead>
                  <tbody>
                    {formData.items.map((item, idx) => (
                      <tr key={item.id} className={editingItemIndex === idx ? 'bg-indigo-50' : ''}>
                        <td className="p-3 border font-mono text-xs">{item.time}</td>
                        <td className="p-3 border">{item.event}</td>
                        <td className="p-3 border text-right">
                          <button type="button" onClick={() => handleEditItemRequest(idx)} className="text-indigo-400 mr-3">✏️</button>
                          <button type="button" onClick={() => handleRemoveItem(item.id)} className="text-red-300">✕</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </form>

            <div className="flex justify-end gap-3 p-6 border-t sticky bottom-0 bg-white rounded-b-3xl">
              <button type="button" onClick={() => setShowForm(false)} className="px-6 py-2.5 text-slate-500 font-bold hover:bg-slate-100 rounded-xl">Batal</button>
              <button 
                type="submit" 
                onClick={(e) => {
                  const form = (e.target as HTMLButtonElement).closest('div')?.previousSibling as HTMLFormElement;
                  if (form && form.checkValidity()) handleSubmit(e as any);
                  else form?.reportValidity();
                }}
                disabled={formData.items.length === 0}
                className="px-8 py-2.5 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-lg disabled:opacity-50"
              >
                Simpan Agenda
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AgendaModule;

import React, { useState } from 'react';
import { User, UserRole } from '../types';

interface UserManagementProps {
  users: User[];
  onUpdateUsers: (users: User[]) => void;
}

const UserManagement: React.FC<UserManagementProps> = ({ users, onUpdateUsers }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [error, setError] = useState('');
  const [formData, setFormData] = useState({
    username: '',
    name: '',
    role: UserRole.STAF_MASUK,
    password: ''
  });

  const resetForm = () => {
    setFormData({ username: '', name: '', role: UserRole.STAF_MASUK, password: '' });
    setEditingUser(null);
    setError('');
  };

  const handleOpenAdd = () => {
    resetForm();
    setIsModalOpen(true);
  };

  const handleOpenEdit = (user: User) => {
    setError('');
    setEditingUser(user);
    setFormData({
      username: user.username,
      name: user.name,
      role: user.role,
      password: user.password || ''
    });
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // Validasi username tidak boleh kosong
    if (!formData.username.trim() || !formData.password.trim()) {
      setError('Username dan Password wajib diisi.');
      return;
    }

    // Cek duplikasi username (hanya jika tambah baru atau ganti username saat edit)
    const isUsernameExists = users.some(u => 
      u.username === formData.username.toLowerCase() && 
      (!editingUser || u.id !== editingUser.id)
    );

    if (isUsernameExists) {
      setError('Username sudah digunakan oleh staf lain.');
      return;
    }

    if (editingUser) {
      // Proses Update (Ubah)
      const updatedUsers = users.map(u => 
        u.id === editingUser.id ? { ...u, ...formData, username: formData.username.toLowerCase() } : u
      );
      onUpdateUsers(updatedUsers);
    } else {
      // Proses Masuk (Tambah Baru)
      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        ...formData,
        username: formData.username.toLowerCase()
      };
      onUpdateUsers([...users, newUser]);
    }

    setIsModalOpen(false);
    resetForm();
  };

  const handleDelete = (id: string, username: string) => {
    // Proteksi: Admin utama tidak boleh dihapus
    if (username === 'admin') {
      alert('Akun administrator utama tidak dapat dihapus demi keamanan sistem.');
      return;
    }

    if (confirm(`Apakah Anda yakin ingin menghapus akses untuk "${username}"? Staf ini tidak akan bisa login lagi.`)) {
      const filteredUsers = users.filter(u => u.id !== id);
      onUpdateUsers(filteredUsers);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white p-6 rounded-2xl shadow-sm border border-slate-100 gap-4">
        <div>
          <h3 className="text-lg font-bold text-slate-800">Daftar Pengguna Sistem</h3>
          <p className="text-sm text-slate-500">Kelola hak akses dan akun staf E-Surat</p>
        </div>
        <button 
          onClick={handleOpenAdd}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2 active:scale-95"
        >
          <span className="text-xl">+</span> Tambah User (Masuk)
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Nama Lengkap</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Username</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Role / Hak Akses</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Tindakan</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {users.map(user => (
                <tr key={user.id} className="hover:bg-indigo-50/30 transition-colors group">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold text-xs">
                        {user.name.charAt(0)}
                      </div>
                      <p className="font-semibold text-slate-800">{user.name}</p>
                    </div>
                  </td>
                  <td className="px-6 py-4 font-mono text-sm text-slate-500">{user.username}</td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-tighter ${
                      user.role === UserRole.ADMIN ? 'bg-purple-100 text-purple-700 border border-purple-200' : 
                      user.role === UserRole.STAF_MASUK ? 'bg-emerald-100 text-emerald-700 border border-emerald-200' : 'bg-blue-100 text-blue-700 border border-blue-200'
                    }`}>
                      {user.role.replace('_', ' ')}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right space-x-2">
                    <button 
                      onClick={() => handleOpenEdit(user)}
                      className="text-indigo-600 hover:text-indigo-800 text-sm font-bold px-3 py-1.5 hover:bg-indigo-100 rounded-lg transition-colors"
                    >
                      Ubah
                    </button>
                    <button 
                      onClick={() => handleDelete(user.id, user.username)}
                      className={`text-red-500 hover:text-red-700 text-sm font-bold px-3 py-1.5 hover:bg-red-50 rounded-lg transition-colors ${user.username === 'admin' ? 'opacity-20 cursor-not-allowed' : ''}`}
                      disabled={user.username === 'admin'}
                    >
                      Hapus
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center z-[110] p-4">
          <div className="bg-white w-full max-w-md rounded-[2rem] shadow-2xl overflow-hidden animate-in zoom-in fade-in duration-300">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-indigo-600 text-white">
              <div className="flex items-center gap-3">
                <span className="text-2xl">{editingUser ? '📝' : '👤'}</span>
                <h2 className="text-xl font-bold">
                  {editingUser ? 'Ubah Profil Staf' : 'Masuk Data Staf Baru'}
                </h2>
              </div>
              <button onClick={() => setIsModalOpen(false)} className="bg-white/20 hover:bg-white/30 p-2 rounded-full transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="p-8 space-y-5">
              {error && (
                <div className="p-3 bg-red-50 text-red-600 text-xs font-bold rounded-xl border border-red-200 flex items-center gap-2 animate-bounce">
                  <span>⚠️</span> {error}
                </div>
              )}

              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Nama Lengkap</label>
                <input 
                  required 
                  value={formData.name} 
                  onChange={e => setFormData({...formData, name: e.target.value})}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all" 
                  placeholder="Nama lengkap staf"
                />
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Username Login</label>
                <input 
                  required 
                  disabled={editingUser?.username === 'admin'}
                  value={formData.username} 
                  onChange={e => setFormData({...formData, username: e.target.value})}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none disabled:bg-slate-100 disabled:text-slate-400 transition-all font-mono" 
                  placeholder="username_akses"
                />
                {editingUser?.username === 'admin' && <p className="text-[10px] text-slate-400 italic">Username admin utama tidak bisa diubah.</p>}
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Password Baru</label>
                <input 
                  type="text"
                  required 
                  value={formData.password} 
                  onChange={e => setFormData({...formData, password: e.target.value})}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all" 
                  placeholder="Password untuk login"
                />
              </div>

              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Tingkat Hak Akses</label>
                <select 
                  disabled={editingUser?.username === 'admin'}
                  value={formData.role} 
                  onChange={e => setFormData({...formData, role: e.target.value as UserRole})}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all"
                >
                  <option value={UserRole.ADMIN}>Administrator (Semua Menu)</option>
                  <option value={UserRole.STAF_MASUK}>Staf Surat Masuk (Input Surat Masuk)</option>
                  <option value={UserRole.STAF_KELUAR}>Staf Surat Keluar (Input Surat Keluar)</option>
                </select>
              </div>

              <div className="flex justify-end gap-3 pt-6 border-t border-slate-100">
                <button 
                  type="button" 
                  onClick={() => setIsModalOpen(false)} 
                  className="px-6 py-3 text-slate-500 font-bold hover:bg-slate-100 rounded-2xl transition-colors"
                >
                  Batalkan
                </button>
                <button 
                  type="submit" 
                  className="px-8 py-3 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95"
                >
                  {editingUser ? 'Simpan Perubahan' : 'Masuk Data Staf'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default UserManagement;

