    const channel = supabase.channel('agendas-changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'agendas' }, () => {
        fetchAgendas();
      })
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, []);

